ALTER TABLE `users` MODIFY COLUMN `email` varchar(320) NOT NULL DEFAULT '';
ALTER TABLE `users` ADD COLUMN IF NOT EXISTS `passwordHash` varchar(256) NOT NULL DEFAULT '';
ALTER TABLE `users` DROP INDEX IF EXISTS `users_openId_unique`;
ALTER TABLE `users` DROP COLUMN IF EXISTS `openId`;
ALTER TABLE `users` DROP COLUMN IF EXISTS `loginMethod`;

CREATE TABLE IF NOT EXISTS `decks` (
  `id` varchar(64) NOT NULL,
  `userId` int NOT NULL,
  `name` varchar(128) NOT NULL,
  `isMain` boolean NOT NULL DEFAULT false,
  `included` boolean NOT NULL DEFAULT true,
  `settings` json,
  `createdAt` timestamp NOT NULL DEFAULT (now()),
  `updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP,
  CONSTRAINT `decks_id` PRIMARY KEY(`id`),
  CONSTRAINT `uq_decks_user_id` UNIQUE(`userId`,`id`)
);

CREATE TABLE IF NOT EXISTS `deck_cards` (
  `id` int AUTO_INCREMENT NOT NULL,
  `deckId` varchar(64) NOT NULL,
  `userId` int NOT NULL,
  `wordId` varchar(128) NOT NULL,
  `addedAt` timestamp NOT NULL DEFAULT (now()),
  CONSTRAINT `deck_cards_id` PRIMARY KEY(`id`),
  CONSTRAINT `uq_deck_cards_deck_word` UNIQUE(`deckId`,`wordId`)
);

ALTER TABLE `sync_flashcards`
  ADD COLUMN IF NOT EXISTS `isLeech` boolean NOT NULL DEFAULT false;

CREATE INDEX IF NOT EXISTS `idx_sync_flashcards_user_due`
  ON `sync_flashcards` (`userId`, `dueDate`);

CREATE INDEX IF NOT EXISTS `idx_sync_flashcards_user_reviewed`
  ON `sync_flashcards` (`userId`, `lastReviewed`);

